INSERT INTO `issues` (`id`,`content_hash`,`title`,`description`,`design`,`acceptance_criteria`,`notes`,`status`,`priority`,`issue_type`,`assignee`,`estimated_minutes`,`created_at`,`created_by`,`owner`,`updated_at`,`closed_at`,`closed_by_session`,`external_ref`,`spec_id`,`compaction_level`,`compacted_at`,`compacted_at_commit`,`original_size`,`sender`,`ephemeral`,`wisp_type`,`pinned`,`is_template`,`crystallizes`,`mol_type`,`work_type`,`quality_score`,`source_system`,`metadata`,`source_repo`,`close_reason`,`event_kind`,`actor`,`target`,`payload`,`await_type`,`await_id`,`timeout_ns`,`waiters`,`hook_bead`,`role_bead`,`agent_state`,`last_activity`,`role_type`,`rig`,`due_at`,`defer_until`) VALUES ('Lifecraft-7cc.6','d4d0fa3eeb3590c357ae5dbb917bbd0316fafc724f0ec2bc3d8514b885ef2419','Setup Dolt Server app on TrueNAS','Configure and deploy a Dolt server as a container/app on TrueNAS (HomePilot).','','','STEPS FOR OWNER (TrueNAS UI):\n1. Create a dataset on TrueNAS (e.g., /mnt/pool/apps/lifecraft-beads) and give \'apps\' user (UID 568) Read/Write access.\n2. In \'Apps\' > \'Discover Apps\' > \'Custom App\', use image \'dolthub/dolt-sql-server:latest\'.\n3. Set environment variables: DOLT_ROOT_HOST=\'%\' and DOLT_ROOT_PASSWORD=\'your_secure_password\'.\n4. Map Host Port 3306 to Container Port 3306.\n5. Map Host Path (your dataset) to Container Path \'/var/lib/dolt\'.\n6. Save and Start.\n\nONCE STARTED:\nProvide me with the TrueNAS IP and the password you chose, and I will help you migrate the current beads and reconfigure \'bd\'.','in_progress',2,'task',NULL,NULL,'2026-04-01 23:36:11','Neil Openshaw','neil.openshaw@gmail.com','2026-04-01 23:38:37',NULL,'',NULL,'',0,NULL,NULL,NULL,'',0,'',0,0,0,'','',NULL,'','{}','','','','','','','','',0,'','','','',NULL,'','',NULL,NULL);
