INSERT INTO `issues` (`id`,`content_hash`,`title`,`description`,`design`,`acceptance_criteria`,`notes`,`status`,`priority`,`issue_type`,`assignee`,`estimated_minutes`,`created_at`,`created_by`,`owner`,`updated_at`,`closed_at`,`closed_by_session`,`external_ref`,`spec_id`,`compaction_level`,`compacted_at`,`compacted_at_commit`,`original_size`,`sender`,`ephemeral`,`wisp_type`,`pinned`,`is_template`,`crystallizes`,`mol_type`,`work_type`,`quality_score`,`source_system`,`metadata`,`source_repo`,`close_reason`,`event_kind`,`actor`,`target`,`payload`,`await_type`,`await_id`,`timeout_ns`,`waiters`,`hook_bead`,`role_bead`,`agent_state`,`last_activity`,`role_type`,`rig`,`due_at`,`defer_until`) VALUES ('Lifecraft-dbi','dbdb1a7a1d0d7c551146cc2af8f15dc205cda31b7b133506af03d1de3b148fb6','EPIC: Legal & Liability Framework','Establishing operating agreements, protecting IP, and separating personal/business liability for the husband-and-wife team.','','','','open',2,'epic',NULL,NULL,'2026-03-31 05:13:20','Neil Openshaw','neil.openshaw@gmail.com','2026-03-31 05:13:20',NULL,'',NULL,'',0,NULL,NULL,NULL,'',0,'',0,0,0,'','',NULL,'','{}','','','','','','','','',0,'','','','',NULL,'','',NULL,NULL);
INSERT INTO `issues` (`id`,`content_hash`,`title`,`description`,`design`,`acceptance_criteria`,`notes`,`status`,`priority`,`issue_type`,`assignee`,`estimated_minutes`,`created_at`,`created_by`,`owner`,`updated_at`,`closed_at`,`closed_by_session`,`external_ref`,`spec_id`,`compaction_level`,`compacted_at`,`compacted_at_commit`,`original_size`,`sender`,`ephemeral`,`wisp_type`,`pinned`,`is_template`,`crystallizes`,`mol_type`,`work_type`,`quality_score`,`source_system`,`metadata`,`source_repo`,`close_reason`,`event_kind`,`actor`,`target`,`payload`,`await_type`,`await_id`,`timeout_ns`,`waiters`,`hook_bead`,`role_bead`,`agent_state`,`last_activity`,`role_type`,`rig`,`due_at`,`defer_until`) VALUES ('Lifecraft-dbi.1','89803a0d72bd35435beb5f6be080a09954c9cb4dc7976cfbbdaa4f6c61b89714','Draft an Operating Agreement','Draft a Shareholders\' Agreement (SHA) for Lifecraft Studios. This document must govern the 50/50 spousal partnership and include clauses for Matrimonial Breakdown (BC Family Law Act), Death/Disability (Buy-Sell), and Deadlock resolution (Shotgun Clause).','','','RESEARCH SUMMARY (BC 2026): \n1. Matrimonial Breakdown: Clause to ensure shares are \'family property\' but remain with the active spouse in case of separation. \n2. Death/Disability: Mandatory buy-sell funded by corporate life insurance. \n3. Shotgun Clause: Irrevocable deadlock-breaking mechanism (Blackmore v. Carmanah ruling). \n4. Transparency Register: Mandatory 15-day reporting for significant individuals. \n5. Section 137 (BCBCA): Note that transferring director powers to shareholders must also be reflected in the company\'s Articles, not just the SHA. \nNEXT STEPS FOR OWNER: \n- Confirm 50/50 ownership split. \n- Define day-to-day management roles (CEO/CTO). \n- Agree on funding mechanisms for capital calls. \n- Decide on mediation vs. immediate Shotgun clause for deadlocks.','open',2,'task',NULL,NULL,'2026-03-31 05:14:35','Neil Openshaw','neil.openshaw@gmail.com','2026-03-31 12:12:49',NULL,'',NULL