INSERT INTO `issues` (`id`,`content_hash`,`title`,`description`,`design`,`acceptance_criteria`,`notes`,`status`,`priority`,`issue_type`,`assignee`,`estimated_minutes`,`created_at`,`created_by`,`owner`,`updated_at`,`closed_at`,`closed_by_session`,`external_ref`,`spec_id`,`compaction_level`,`compacted_at`,`compacted_at_commit`,`original_size`,`sender`,`ephemeral`,`wisp_type`,`pinned`,`is_template`,`crystallizes`,`mol_type`,`work_type`,`quality_score`,`source_system`,`metadata`,`source_repo`,`close_reason`,`event_kind`,`actor`,`target`,`payload`,`await_type`,`await_id`,`timeout_ns`,`waiters`,`hook_bead`,`role_bead`,`agent_state`,`last_activity`,`role_type`,`rig`,`due_at`,`defer_until`) VALUES ('Lifecraft-ok1.1','44938b156c3fb05b15de40978853ec1347d3277cd799332938a20ffa5e3e585e','Compare business banking options','Compare business banking for Lifecraft Studios. Focus on multi-product separation and CAD/USD interest rates.','','','RESEARCH SUMMARY (Canada 2026):\n1. BEST FOR TECH/USD: Venn (Vault) - 2% interest, unlimited sub-accounts, local USD/GBP/EUR details.\n2. BEST FOR YIELD: Float - 4% interest, separate wallets/cards per product (e.g., Homestead wallet).\n3. BEST FOR TRADITIONAL: BMO eBusiness - /bin/bash monthly fees for unlimited digital accounts.\n4. BEST FOR MOBILE/LIMITS: RBC Digital Choice - /mo, high e-transfer limits, robust app.\n\nNEXT STEPS FOR OWNER:\n- Decide if you need local USD/GBP/EUR account details for global sales.\n- Determine if \'separate wallets/cards\' (Float) or \'separate bank accounts\' (BMO/Venn) is better for your bookkeeping style.','open',2,'task',NULL,NULL,'2026-03-31 05:14:12','Neil Openshaw','neil.openshaw@gmail.com','2026-03-31 12:14:14',NULL,'',NULL,'',0,NULL,NULL,NULL,'',0,'',0,0,0,'','',NULL,'','{}','','','','','','','','',0,'','','','',NULL,'','',NULL,NULL);
